var gemini = items[0].json;
var week = $('Fetch Week Data').first().json;

var content = (gemini.content && gemini.content.parts && gemini.content.parts[0] && gemini.content.parts[0].text)
  || (gemini.parts && gemini.parts[0] && gemini.parts[0].text)
  || gemini.text
  || JSON.stringify(gemini);

if (typeof content !== 'string') content = JSON.stringify(content);
content = content.replace(/\\n/g, '\n');

var weekNum = week.week_number || 1;
var topic = String(week.topic || 'Untitled');
var teachingNotes = String(week.teaching_notes || '');

function parseArr(d) {
  if (!d) return [];
  if (Array.isArray(d)) return d.map(String);
  if (typeof d === 'string') {
    try {
      var p = JSON.parse(d);
      return Array.isArray(p) ? p.map(String) : [d];
    } catch(e) { return [d]; }
  }
  return [];
}

var objectives = parseArr(week.learning_objectives);
var prompts = parseArr(week.discussion_prompts);
var activities = parseArr(week.activity_ideas);

function esc(s) {
  return String(s || '').replace(/[\\()]/g, function(m) { return '\\' + m; }).replace(/[^\x20-\x7E]/g, '');
}

function wrap(text, maxLen) {
  var words = String(text).split(' ');
  var lines = [];
  var line = '';
  for (var i = 0; i < words.length; i++) {
    if ((line + words[i]).length > maxLen && line) {
      lines.push(line.trim());
      line = words[i] + ' ';
    } else {
      line += words[i] + ' ';
    }
  }
  if (line.trim()) lines.push(line.trim());
  return lines;
}

var BLUE   = '0.0 0.4 0.8';
var DARK   = '0.13 0.13 0.16';
var MID    = '0.35 0.35 0.4';
var GREEN  = '0.15 0.68 0.38';
var ORANGE = '0.9 0.5 0.13';
var PURPLE = '0.56 0.27 0.68';
var LINE_C = '0.85 0.85 0.88';

var pages = [];

function newPage() {
  var p = { cmds: [], y: 790 };
  pages.push(p);
  return p;
}

function addFooter(p) {
  p.cmds.push(LINE_C + ' RG 0.3 w 50 42 m 545 42 l S');
  p.cmds.push('0.65 0.65 0.68 rg');
  p.cmds.push('BT /F1 7 Tf 50 30 Td (Teaching Genome  |  Week ' + weekNum + '  |  Page ' + pages.length + ') Tj ET');
}

function addTextBlock(p, text, fs, color, indent) {
  fs = fs || 10;
  indent = indent || 50;
  var maxC = Math.floor((495 - (indent - 50)) / (fs * 0.48));
  var tLines = String(text).split('\n');
  for (var t = 0; t < tLines.length; t++) {
    var wl = wrap(tLines[t], maxC);
    if (wl.length === 0) { p.y -= 8; continue; }
    for (var w = 0; w < wl.length; w++) {
      if (p.y < 60) { addFooter(p); p = newPage(); }
      p.cmds.push((color || DARK) + ' rg');
      p.cmds.push('BT /F1 ' + fs + ' Tf ' + indent + ' ' + p.y + ' Td (' + esc(wl[w]) + ') Tj ET');
      p.y -= (fs + 4);
    }
  }
  return p;
}

function addBullets(p, items, color) {
  for (var i = 0; i < items.length; i++) {
    if (p.y < 60) { addFooter(p); p = newPage(); }
    p.cmds.push((color || BLUE) + ' rg');
    p.cmds.push('50 ' + (p.y + 2) + ' 5 5 re f');
    var bl = wrap(items[i], 72);
    for (var b = 0; b < bl.length; b++) {
      if (p.y < 55) { addFooter(p); p = newPage(); }
      p.cmds.push(DARK + ' rg');
      p.cmds.push('BT /F1 10 Tf 62 ' + p.y + ' Td (' + esc(bl[b]) + ') Tj ET');
      p.y -= 14;
    }
    p.y -= 3;
  }
  return p;
}

function sectionTitle(p, title, color) {
  if (p.y < 120) { addFooter(p); p = newPage(); }
  p.cmds.push(LINE_C + ' RG 0.3 w 50 ' + p.y + ' m 545 ' + p.y + ' l S');
  p.y -= 22;
  p.cmds.push((color || BLUE) + ' rg');
  p.cmds.push('BT /F2 13 Tf 50 ' + p.y + ' Td (' + esc(title) + ') Tj ET');
  p.y -= 20;
  return p;
}

// PAGE 1: Title
var p = newPage();
p.cmds.push('0.0 0.3 0.65 rg');
p.cmds.push('0 750 595.28 91.89 re f');
p.cmds.push('1 1 1 rg');
p.cmds.push('BT /F2 28 Tf 50 780 Td (Week ' + weekNum + ') Tj ET');
p.cmds.push('0.7 0.85 1 rg');
p.cmds.push('BT /F1 14 Tf 50 758 Td (Teaching Genome) Tj ET');
p.y = 710;
p.cmds.push(DARK + ' rg');
p.cmds.push('BT /F2 20 Tf 50 ' + p.y + ' Td (' + esc(topic) + ') Tj ET');
p.y -= 10;
p.cmds.push(BLUE + ' RG 1 w 50 ' + p.y + ' m 200 ' + p.y + ' l S');
p.y -= 30;

if (objectives.length > 0) { p = sectionTitle(p, 'LEARNING OBJECTIVES', GREEN); p = addBullets(p, objectives, GREEN); p.y -= 10; }
if (prompts.length > 0)    { p = sectionTitle(p, 'DISCUSSION TOPICS', BLUE);     p = addBullets(p, prompts, BLUE);     p.y -= 10; }

if (activities.length > 0) {
  p = sectionTitle(p, 'ACTIVITIES', ORANGE);
  for (var a = 0; a < activities.length; a++) {
    if (p.y < 60) { addFooter(p); p = newPage(); }
    p.cmds.push(ORANGE + ' rg');
    p.cmds.push('BT /F2 10 Tf 50 ' + p.y + ' Td (' + (a + 1) + '.) Tj ET');
    var al = wrap(activities[a], 72);
    for (var x = 0; x < al.length; x++) {
      p.cmds.push(DARK + ' rg');
      p.cmds.push('BT /F1 10 Tf 70 ' + p.y + ' Td (' + esc(al[x]) + ') Tj ET');
      p.y -= 14;
    }
    p.y -= 4;
  }
}
addFooter(p);

// GEMINI CONTENT PAGES
var contentLines = content.split('\n');
var sections = [];
var curT = 'Lecture Content';
var curB = [];

for (var i = 0; i < contentLines.length; i++) {
  var ln = contentLines[i].trim();
  if (ln.match(/^SECTION:\s+/) || ln.match(/^#{1,3}\s+/) || ln.match(/^\*\*[^*]+\*\*$/)) {
    if (curB.length > 0) sections.push({ title: curT, body: curB.join('\n').trim() });
    curT = ln.replace(/^SECTION:\s+/, '').replace(/^#{1,3}\s+/, '').replace(/^\*\*/, '').replace(/\*\*$/, '').trim();
    curB = [];
  } else if (ln.length > 0) {
    curB.push(ln);
  }
}
if (curB.length > 0) sections.push({ title: curT, body: curB.join('\n').trim() });
if (sections.length === 0) sections.push({ title: 'Lecture Content', body: content });

var colors = [BLUE, GREEN, PURPLE, ORANGE];

for (var s = 0; s < sections.length; s++) {
  var sec = sections[s];
  if (!sec.body.trim()) continue;
  p = newPage();
  var sc = colors[s % 4];
  p.cmds.push(sc + ' rg');
  p.cmds.push('0 800 595.28 41.89 re f');
  p.cmds.push('1 1 1 rg');
  p.cmds.push('BT /F2 18 Tf 50 812 Td (' + esc(sec.title) + ') Tj ET');
  p.y = 775;

  var bLines = sec.body.split('\n');
  for (var b = 0; b < bLines.length; b++) {
    var bl = bLines[b].trim();
    if (!bl) { p.y -= 8; continue; }
    if (bl.match(/^[-\*]\s+/)) {
      var bt = bl.replace(/^[-\*]\s+/, '').replace(/^\*\*/, '').replace(/\*\*/g, '');
      if (p.y < 60) { addFooter(p); p = newPage(); }
      p.cmds.push(sc + ' rg');
      p.cmds.push('55 ' + (p.y + 2) + ' 4 4 re f');
      var bw = wrap(bt, 72);
      for (var w = 0; w < bw.length; w++) {
        if (p.y < 55) { addFooter(p); p = newPage(); }
        p.cmds.push(DARK + ' rg');
        p.cmds.push('BT /F1 10 Tf 66 ' + p.y + ' Td (' + esc(bw[w]) + ') Tj ET');
        p.y -= 14;
      }
      p.y -= 2;
    } else {
      var clean = bl.replace(/\*\*/g, '');
      p = addTextBlock(p, clean, 10, DARK, 50);
      p.y -= 2;
    }
  }
  addFooter(p);
}

// TEACHING NOTES PAGE
if (teachingNotes) {
  p = newPage();
  p.cmds.push(PURPLE + ' rg');
  p.cmds.push('0 800 595.28 41.89 re f');
  p.cmds.push('1 1 1 rg');
  p.cmds.push('BT /F2 18 Tf 50 812 Td (Teaching Strategy) Tj ET');
  p.y = 775;
  p = addTextBlock(p, teachingNotes, 10, MID, 50);
  addFooter(p);
}

// ASSEMBLE PDF
var pageContents = [];
for (var i = 0; i < pages.length; i++) pageContents.push(pages[i].cmds.join('\n'));

var pdf = '%PDF-1.4\n';
var offsets = [];

function addObj(ct) {
  offsets.push(pdf.length);
  pdf += ct + '\n';
}

addObj('1 0 obj\n<< /Type /Catalog /Pages 2 0 R >>\nendobj');

var kids = [];
for (var i = 0; i < pages.length; i++) kids.push((3 + i * 2) + ' 0 R');
addObj('2 0 obj\n<< /Type /Pages /Kids [' + kids.join(' ') + '] /Count ' + pages.length + ' >>\nendobj');

var f1 = 3 + pages.length * 2;
var f2 = f1 + 1;

for (var i = 0; i < pages.length; i++) {
  var pid = 3 + i * 2;
  var cid = 4 + i * 2;
  addObj(pid + ' 0 obj\n<< /Type /Page /Parent 2 0 R /MediaBox [0 0 595.28 841.89] /Contents ' + cid + ' 0 R /Resources << /Font << /F1 ' + f1 + ' 0 R /F2 ' + f2 + ' 0 R >> >> >>\nendobj');
  addObj(cid + ' 0 obj\n<< /Length ' + pageContents[i].length + ' >>\nstream\n' + pageContents[i] + '\nendstream\nendobj');
}

addObj(f1 + ' 0 obj\n<< /Type /Font /Subtype /Type1 /BaseFont /Helvetica >>\nendobj');
addObj(f2 + ' 0 obj\n<< /Type /Font /Subtype /Type1 /BaseFont /Helvetica-Bold >>\nendobj');

var total = f2 + 1;
var xref = pdf.length;
pdf += 'xref\n0 ' + total + '\n0000000000 65535 f \n';
for (var i = 0; i < offsets.length; i++) pdf += String(offsets[i]).padStart(10, '0') + ' 00000 n \n';
pdf += 'trailer\n<< /Size ' + total + ' /Root 1 0 R >>\nstartxref\n' + xref + '\n%%EOF';

return [{ json: { pdfData: pdf, fileName: 'Week_' + weekNum + '_Slides.pdf' } }];

const pdfData = $input.first().json.pdfData;
const fileName = $input.first().json.fileName || 'slides.pdf';
const pdfBuffer = Buffer.from(pdfData, 'latin1');
const binaryData = await this.helpers.prepareBinaryData(pdfBuffer, fileName, 'application/pdf');
return [{ json: { fileName }, binary: { data: binaryData } }];
